 1→import { Link } from 'react-router-dom'
 2→import { Card, Text, Group, Badge, Box } from '@mantine/core'
 3→
 4→interface ItemCardItem {
 5→  id: string
 6→  type: string
 7→  title: string | null
 8→  contentText: string | null
 9→  tags: string[]
10→  source: string
11→  sourceUrl: string | null
12→  capturedAt: string
13→}
14→
15→interface ItemCardProps {
16→  item: ItemCardItem
17→  compact?: boolean
18→}
19→
20→const TYPE_COLORS: Record<string, string> = {
21→  BOOKMARK: 'blue',
22→  TEXT_NOTE: 'green',
23→  VOICE_NOTE: 'orange',
24→  DRIVE_DOC: 'violet',
25→  HIGHLIGHT: 'yellow',
26→  FILE: 'gray',
27→}
28→
29→function formatDate(dateStr: string): string {
30→  return new Date(dateStr).toLocaleDateString()
31→}
32→
33→function formatType(type: string): string {
34→  return type.replace(/_/g, ' ').toLowerCase()
35→}
36→
37→export function ItemCard({ item, compact }: ItemCardProps) {
38→  return (
39→    <Card
40→      component={Link}
41→      to={`/items/${item.id}`}
42→      shadow="xs"
43→      padding={compact ? 'sm' : 'md'}
44→      radius="md"
45→      withBorder
46→      style={{ textDecoration: 'none', color: 'inherit' }}
47→    >
48→      <Group justify="space-between" mb={compact ? 4 : 'xs'}>
49→        <Text fw={600} fz={compact ? 'sm' : 'md'} lineClamp={1} style={{ flex: 1 }}>
50→          {item.title ?? 'Untitled'}
51→        </Text>
52→        <Badge size="sm" variant="light" color={TYPE_COLORS[item.type] ?? 'gray'}>
53→          {formatType(item.type)}
54→        </Badge>
55→      </Group>
56→      {!compact && item.contentText && (
57→        <Text fz="sm" c="dimmed" lineClamp={2}>
58→          {item.contentText}
59→        </Text>
60→      )}
61→      <Group gap="xs" mt={compact ? 4 : 'xs'}>
62→        {item.tags.slice(0, compact ? 3 : 5).map((tag) => (
63→          <Badge key={tag} size="xs" variant="outline">
64→            {tag}
65→          </Badge>
66→        ))}
67→        {item.tags.length > (compact ? 3 : 5) && (
68→          <Box component="span">
69→            <Text fz="xs" c="dimmed">
70→              +{item.tags.length - (compact ? 3 : 5)}
71→            </Text>
72→          </Box>
73→        )}
74→        <Text fz="xs" c="dimmed" ml="auto">
75→          {formatDate(item.capturedAt)}
76→        </Text>
77→      </Group>
78→    </Card>
79→  )
80→}
